+
+function isSafeTimezone(timezone) {
+  if (!timezone) return false;
+  if (typeof timezone !== 'string') return false;
+  if (timezone.length > 100) return false;
+  return SAFE_TIMEZONE_REGEX.test(timezone);
+}
+
