@@ -0,0 +1,15 @@
+'use strict';
+
+/**
+ * Validates that an identifier is safe to use in code generation.
+ * Only allows alphanumeric characters and underscores,
+ * preventing code injection through malicious field names.
+ * @param {string} str - The identifier to validate
+ * @returns {boolean} - True if the identifier is safe
+ */
+function isSafeIdentifier(str) {
+  if (typeof str !== 'string') return false;
+  if (str.length === 0) return false;
+  // Must start with letter or underscore, then alphanumeric or underscore
+  return /^[a-zA-Z_][a-zA-Z0-9_]*$/.test(str);
+}
+
+module.exports = { isSafeIdentifier };
